import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
vi.mock("node:child_process", () => ({
    execFileSync: vi.fn(),
    spawn: vi.fn(() => ({ on: vi.fn() })),
}));
import { execFileSync, spawn } from "node:child_process";
import { recordFocus } from "./frontmostApp.js";
const mockedExecFileSync = vi.mocked(execFileSync);
const mockedSpawn = vi.mocked(spawn);
describe("recordFocus", () => {
    const originalPlatform = process.platform;
    const originalPpid = process.ppid;
    const originalEnv = { ...process.env };
    beforeEach(() => {
        vi.clearAllMocks();
        delete process.env.WINDOWID;
        delete process.env.ITERM_SESSION_ID;
    });
    afterEach(() => {
        Object.defineProperty(process, "platform", { value: originalPlatform });
        Object.defineProperty(process, "ppid", {
            value: originalPpid,
            configurable: true,
        });
        process.env = { ...originalEnv };
    });
    describe("macOS process tree (primary)", () => {
        beforeEach(() => {
            Object.defineProperty(process, "platform", { value: "darwin" });
            Object.defineProperty(process, "ppid", {
                value: 200,
                configurable: true,
            });
        });
        it("walks process tree to find ancestor .app and activates it", () => {
            mockedExecFileSync.mockImplementation(((cmd, args) => {
                if (cmd === "ps" && args[3] === "200") {
                    return "  100 /bin/zsh\n";
                }
                if (cmd === "ps" && args[3] === "100") {
                    return "   50 /Applications/Superset.app/Contents/MacOS/Superset\n";
                }
                return "";
            }));
            const restore = recordFocus();
            restore();
            expect(mockedSpawn).toHaveBeenCalledWith("osascript", ["-e", 'tell application "Superset" to activate'], expect.objectContaining({ stdio: "ignore" }));
        });
        it("stops at the first .app ancestor", () => {
            mockedExecFileSync.mockImplementation(((cmd, args) => {
                if (cmd === "ps" && args[3] === "200") {
                    return "  100 /Applications/iTerm.app/Contents/MacOS/iTerm2\n";
                }
                return "";
            }));
            const restore = recordFocus();
            restore();
            expect(mockedExecFileSync).not.toHaveBeenCalledWith("ps", expect.arrayContaining(["100"]), expect.anything());
        });
        it("does not call osascript frontmost capture when .app ancestor found", () => {
            mockedExecFileSync.mockImplementation(((cmd, args) => {
                if (cmd === "ps" && args[3] === "200") {
                    return "  1 /Applications/Terminal.app/Contents/MacOS/Terminal\n";
                }
                return "";
            }));
            recordFocus();
            expect(mockedExecFileSync).not.toHaveBeenCalledWith("osascript", expect.anything(), expect.anything());
        });
        it("detects iTerm2 by bundle name and uses session targeting", () => {
            process.env.ITERM_SESSION_ID = "w0t0p0:8A7B-1234";
            mockedExecFileSync.mockImplementation(((cmd, args) => {
                if (cmd === "ps" && args[3] === "200") {
                    return "  1 /Applications/iTerm.app/Contents/MacOS/iTerm2\n";
                }
                return "";
            }));
            const restore = recordFocus();
            restore();
            const args = mockedSpawn.mock.calls[0][1];
            expect(args[1]).toContain('tell application "iTerm2"');
            expect(args[1]).toContain("activate");
            expect(args[1]).toContain('if id of s is "w0t0p0:8A7B-1234"');
        });
        it("falls back to app-level iTerm2 activate without session ID", () => {
            mockedExecFileSync.mockImplementation(((cmd, args) => {
                if (cmd === "ps" && args[3] === "200") {
                    return "  1 /Applications/iTerm.app/Contents/MacOS/iTerm2\n";
                }
                return "";
            }));
            const restore = recordFocus();
            restore();
            expect(mockedSpawn).toHaveBeenCalledWith("osascript", ["-e", 'tell application "iTerm2" to activate'], expect.objectContaining({ stdio: "ignore" }));
        });
        it("captures ITERM_SESSION_ID at record time, not restore time", () => {
            process.env.ITERM_SESSION_ID = "w0t0p0:RECORD-TIME";
            mockedExecFileSync.mockImplementation(((cmd, args) => {
                if (cmd === "ps" && args[3] === "200") {
                    return "  1 /Applications/iTerm.app/Contents/MacOS/iTerm2\n";
                }
                return "";
            }));
            const restore = recordFocus();
            process.env.ITERM_SESSION_ID = "w0t0p0:CHANGED-LATER";
            restore();
            const args = mockedSpawn.mock.calls[0][1];
            expect(args[1]).toContain('if id of s is "w0t0p0:RECORD-TIME"');
            expect(args[1]).not.toContain("CHANGED-LATER");
        });
        it("sanitizes ITERM_SESSION_ID containing quotes", () => {
            process.env.ITERM_SESSION_ID = 'w0t0p0:"injected';
            mockedExecFileSync.mockImplementation(((cmd, args) => {
                if (cmd === "ps" && args[3] === "200") {
                    return "  1 /Applications/iTerm.app/Contents/MacOS/iTerm2\n";
                }
                return "";
            }));
            const restore = recordFocus();
            restore();
            expect(mockedSpawn).toHaveBeenCalledWith("osascript", ["-e", 'tell application "iTerm2" to activate'], expect.objectContaining({ stdio: "ignore" }));
        });
        it("handles app paths with spaces", () => {
            mockedExecFileSync.mockImplementation(((cmd, args) => {
                if (cmd === "ps" && args[3] === "200") {
                    return "  1 /Applications/Visual Studio Code.app/Contents/MacOS/Electron\n";
                }
                return "";
            }));
            const restore = recordFocus();
            restore();
            expect(mockedSpawn).toHaveBeenCalledWith("osascript", ["-e", 'tell application "Visual Studio Code" to activate'], expect.objectContaining({ stdio: "ignore" }));
        });
    });
    describe("macOS frontmost fallback", () => {
        beforeEach(() => {
            Object.defineProperty(process, "platform", { value: "darwin" });
            Object.defineProperty(process, "ppid", {
                value: 200,
                configurable: true,
            });
        });
        it("falls back to frontmost when no .app ancestor found", () => {
            mockedExecFileSync.mockImplementation(((cmd, args) => {
                if (cmd === "ps" && args[3] === "200") {
                    return "  1 /sbin/launchd\n";
                }
                if (cmd === "osascript") {
                    return "Safari\n";
                }
                return "";
            }));
            const restore = recordFocus();
            restore();
            expect(mockedSpawn).toHaveBeenCalledWith("osascript", ["-e", 'tell application "Safari" to activate'], expect.objectContaining({ stdio: "ignore" }));
        });
        it("falls back to frontmost when ps fails", () => {
            mockedExecFileSync.mockImplementation(((cmd) => {
                if (cmd === "ps") {
                    throw new Error("ps not found");
                }
                if (cmd === "osascript") {
                    return "Terminal\n";
                }
                return "";
            }));
            const restore = recordFocus();
            restore();
            expect(mockedSpawn).toHaveBeenCalledWith("osascript", ["-e", 'tell application "Terminal" to activate'], expect.objectContaining({ stdio: "ignore" }));
        });
        it("no-ops when both process tree and frontmost capture fail", () => {
            mockedExecFileSync.mockImplementation(() => {
                throw new Error("not found");
            });
            const restore = recordFocus();
            restore();
            expect(mockedSpawn).not.toHaveBeenCalled();
        });
    });
    describe("Linux WINDOWID (primary)", () => {
        beforeEach(() => {
            Object.defineProperty(process, "platform", { value: "linux" });
        });
        it("uses WINDOWID env var for exact window focus", () => {
            process.env.WINDOWID = "67108864";
            const restore = recordFocus();
            restore();
            expect(mockedSpawn).toHaveBeenCalledWith("xdotool", ["windowactivate", "67108864"], expect.objectContaining({ stdio: "ignore" }));
        });
        it("skips frontmost capture when WINDOWID is set", () => {
            process.env.WINDOWID = "67108864";
            recordFocus();
            expect(mockedExecFileSync).not.toHaveBeenCalled();
        });
    });
    describe("Linux frontmost fallback", () => {
        beforeEach(() => {
            Object.defineProperty(process, "platform", { value: "linux" });
        });
        it("captures active window via xdotool when no WINDOWID", () => {
            mockedExecFileSync.mockReturnValue("12345678\n");
            recordFocus();
            expect(mockedExecFileSync).toHaveBeenCalledWith("xdotool", ["getactivewindow"], expect.objectContaining({ stdio: "pipe", encoding: "utf-8" }));
        });
        it("restores focus via xdotool windowactivate", () => {
            mockedExecFileSync.mockReturnValue("12345678\n");
            const restore = recordFocus();
            restore();
            expect(mockedSpawn).toHaveBeenCalledWith("xdotool", ["windowactivate", "12345678"], expect.objectContaining({ stdio: "ignore" }));
        });
    });
    describe("Windows (frontmost only)", () => {
        beforeEach(() => {
            Object.defineProperty(process, "platform", { value: "win32" });
        });
        it("captures foreground window via PowerShell GetForegroundWindow", () => {
            mockedExecFileSync.mockReturnValue("131586\n");
            recordFocus();
            expect(mockedExecFileSync).toHaveBeenCalledWith("powershell.exe", [
                "-NoProfile",
                "-Command",
                expect.stringContaining("GetForegroundWindow"),
            ], expect.objectContaining({
                stdio: "pipe",
                encoding: "utf-8",
                timeout: 5000,
            }));
        });
        it("constructs valid DllImport with correct quoting in capture command", () => {
            mockedExecFileSync.mockReturnValue("131586\n");
            recordFocus();
            const args = mockedExecFileSync.mock.calls[0][1];
            const command = args[2];
            expect(command).toContain('[DllImport("user32.dll")]');
            expect(command).toContain("-Name WinFocus -Namespace Bitfab");
            expect(command).toContain("[Bitfab.WinFocus]::GetForegroundWindow().ToInt64()");
        });
        it("restores focus with Alt key trick before SetForegroundWindow", () => {
            mockedExecFileSync.mockReturnValue("131586\n");
            const restore = recordFocus();
            restore();
            const args = mockedSpawn.mock.calls[0][1];
            const script = args[2];
            expect(script).toContain('[DllImport("user32.dll")]');
            expect(script).toContain("keybd_event(0x12, 0, 1,");
            expect(script).toContain("SetForegroundWindow([IntPtr]::new(131586))");
            expect(script).toContain("keybd_event(0x12, 0, 3,");
        });
        it("rejects non-numeric HWND to prevent command injection", () => {
            mockedExecFileSync.mockReturnValue("not-a-number\n");
            const restore = recordFocus();
            restore();
            expect(mockedSpawn).not.toHaveBeenCalled();
        });
        it("accepts large HWND values", () => {
            mockedExecFileSync.mockReturnValue("140737488355328\n");
            const restore = recordFocus();
            restore();
            const args = mockedSpawn.mock.calls[0][1];
            expect(args[2]).toContain("[IntPtr]::new(140737488355328)");
        });
    });
    describe("unsupported platforms", () => {
        it("returns no-op restore on unsupported platform", () => {
            Object.defineProperty(process, "platform", { value: "freebsd" });
            const restore = recordFocus();
            expect(mockedExecFileSync).not.toHaveBeenCalled();
            restore();
            expect(mockedSpawn).not.toHaveBeenCalled();
        });
    });
});
